class Solution:
    def solve(self, graph, n):
        visited = [False] * n
        for i in range(n):
            if not visited[i]:
                if self.dfs(graph, i, visited, -1): return True
        return False

def main():
    s = Solution()
    n = int(input())
    graph = [[] for _ in range(n)]
    for _ in range(n-1):
        u, v = map(int, input().split())
        graph[u].append(v)
    print('1' if s.solve(graph, n) else '0')
